"use client"

import { Swiper, SwiperSlide } from "swiper/react"
import "swiper/css"

const blogs = [
{
title:"How to Choose the Right College in India",
category:"College Guide",
date:"March 2026",
image:"https://images.unsplash.com/photo-1523240795612-9a054b0db644"
},
{
title:"Top Engineering Colleges in India",
category:"Engineering",
date:"March 2026",
image:"https://images.unsplash.com/photo-1562774053-701939374585"
},
{
title:"Best MBA Colleges for Management Studies",
category:"MBA",
date:"February 2026",
image:"https://images.unsplash.com/photo-1551836022-d5d88e9218df"
},
{
title:"How to Prepare for NEET Exam",
category:"Medical",
date:"February 2026",
image:"data:image/jpeg;base64,"
},
{
title:"Study Abroad Guide for Indian Students",
category:"Study Abroad",
date:"January 2026",
image:"https://images.unsplash.com/photo-1503676260728-1c00da094a0b"
},
{
title:"Scholarships Available for Indian Students",
category:"Scholarships",
date:"January 2026",
image:"https://images.unsplash.com/photo-1498243691581-b145c3f54a5a"
}
]

export default function Blogs(){

return(

<section className="py-20 bg-white">

<div className="max-w-7xl mx-auto px-6">

{/* Heading */}

<div className="flex justify-between items-center mb-12">

<div>

<h2 className="text-3xl font-bold text-[#1e3a5f]">
Latest Blogs
</h2>

<p className="text-gray-600 mt-2">
Explore insights, tips and guides for students
</p>

</div>

<button className="text-orange-500 font-medium">
View All →
</button>

</div>


{/* Blog Slider */}

<Swiper
spaceBetween={25}
slidesPerView={1}
breakpoints={{
640:{slidesPerView:2},
768:{slidesPerView:3},
1024:{slidesPerView:4}
}}
>

{blogs.map((blog,index)=>(

<SwiperSlide key={index}>

<div className="bg-white rounded-xl shadow hover:shadow-xl transition overflow-hidden">

{/* Image */}

<div className="relative h-44">

<img
src={blog.image}
alt={blog.title}
className="w-full h-full object-cover"
/>

{/* Category */}

<div className="absolute top-3 left-3 bg-orange-500 text-white text-xs px-3 py-1 rounded">

{blog.category}

</div>

</div>


{/* Content */}

<div className="p-5">

<p className="text-xs text-gray-400 mb-2">
{blog.date}
</p>

<h3 className="text-lg font-semibold text-black leading-snug">

{blog.title}

</h3>

<button className="mt-4 text-orange-500 text-sm font-medium hover:underline">

Read More →

</button>

</div>

</div>

</SwiperSlide>

))}

</Swiper>

</div>

</section>

)
}